            SELECT id, name, status, branch_id
                FROM drivers
                WHERE id = $1`
        const result = await pool.query(query, [id])
        if (result.rows.length === 0) {return res.status(404).json({error: `Geen drivers gevonden voor dit id: ${id}`})}
        res.status(200).json(result.rows[0])
